/* ====== 全局字体设置 ====== */
@import url("https://fontsapi.zeoseven.com/25/main/result.css");

body {
    font-family: "WenQuanYi Micro Hei";
    font-weight: normal;
}
/*———————— 移动端顶栏背景 ————————*/
#top-bar {
    position: fixed !important;  /* 改为固定定位适配移动端 */
    overflow: visible !important;
    background: none !important;
    border: 0 !important;
    box-shadow: none !important;
    pointer-events: none;
    width: 100vw;  /* 全屏宽度 */
    height: 90px;  /* 适合移动端的顶部高度 */
    top: 0;
    left: 0;
}

#top-bar::before {
    content: "";
    position: fixed;
    background: url("https://i.postimg.cc/9M40wQFC/retouch-2025052922133392.png") no-repeat center / cover;  /* 使用cover适配屏幕 */

    /* 移动端适配定位 */
    top: 0px;
    left: 0px;
    right: 2px;
    bottom: 0px;

    /* 层级控制 */
    z-index: 3004;
    pointer-events: auto;

    /* 移除动画相关属性 */
    transform: none !important;
    animation: none !important;
}

/* —————面板背景图———— */
.drawer-content {
  background-image: url('https://i.postimg.cc/WzDPgpK6/retouch-2025052918250700.jpg'); /* 示例图片URL */
  background-size: cover; /* 图片覆盖整个元素 */
  background-position: center; /* 图片居中显示 */
  background-repeat: no-repeat; /* 图片不重复 */
  background-attachment: fixed; /* 固定背景图片 */
}

/*——————滑块——————*/
input[type="range"]::-webkit-slider-thumb {
  -webkit-appearance: none;
  appearance: none;
  width: 35px;
  height: 35px;
  background: transparent url('https://i.postimg.cc/7Zy5kF7B/retouch-2025052920213804.png') center/cover no-repeat;
  border: none;
  border-radius: 0;
  box-shadow: none;
  cursor: ew-resize;
  position: relative;
  z-index: 1;
}

/*——————装饰层——————*/
/* /* ==============================================
 * 1. 装饰层模块
 * ==============================================*/
/* 上层装饰层 - 位于气泡上方 */
.mes::before {
  content: "";
  position: absolute;
  top: -197px; /* 调整上层装饰层与气泡顶部的距离(负值表示向上) */
  left: 0.2px; /* 调整上层装饰层的水平位置 */
  width: 349.970px; /* 调整上层装饰层的宽度 */
  height: 351.6px; /* 调整上层装饰层的高度 */
  background-image: url('https://i.postimg.cc/KvzZMHYQ/retouch_2025052919255625.png'); /* 替换为你的图片链接 - 上层装饰层图片 */
  background-size: contain; /* 图片适应容器尺寸 */
  background-repeat: no-repeat; /* 不重复显示图片 */
  z-index: 40; /* 确保在气泡上方 */
  pointer-events: none; /* 避免阻挡鼠标事件 */
}



/* 下层装饰层 - 位于气泡下方，跟随气泡尾部移动 */
.mes::after {
  content: "";
  position: absolute;
  bottom: -365px; /* 调整下层装饰层与气泡底部的距离(负值表示向下) */
  right: 0px; /* 调整下层装饰层的水平位置 */
  width: 350.5px; /* 调整下层装饰层的宽度 */
  height: 370px; /* 调整下层装饰层的高度 */
  background-image: url('https://i.postimg.cc/q7hC5p2g/retouch_2025052918114911.png'); /* 替换为你的图片链接 - 下层装饰层图片 */
  background-size: contain; /* 图片适应容器尺寸 */
  background-repeat: no-repeat; /* 不重复显示图片 */
  z-index: 42; /* 确保在气泡上方 */
  pointer-events: none; /* 避免阻挡鼠标事件 */
}

/*——————修复右边距过大——————*/
/* 消息文本容器（可独立调整上下左右边距） */
.mes_text, 
.mes_reasoning {
    /* 基础样式 */
    font-weight: 500;
    line-height: calc(var(--mainFontSize) + .5rem);
    text-align: left; /* 文本左对齐 */
    overflow-wrap: anywhere;

    /* 可独立调整的边距系统 */
    --top-padding: 3rem; /* 气泡顶部留白（可单独调整） */
    --bottom-padding: 3.2rem; /* 气泡底部留白（可单独调整） */
    --left-padding: 0.4rem; /* 气泡左边距（控制文本与左侧边界距离） */
    --right-padding: 0.5rem; /* 气泡右边距（控制文本与右侧边界距离） */

    padding-top: var(--top-padding);
    padding-bottom: var(--bottom-padding);
    padding-left: var(--left-padding);
    padding-right: var(--right-padding);

    /* 最大宽度控制 */
    max-width: 700%;
    margin: 0; /* 清除默认外边距 */

    /* 气泡视觉相关样式（可根据UI需求扩展） */
    /* background-color: #f0f0f0; */
    /* border-radius: 19px; */
}



