/*——————气泡设置——————*/

/* ==============================================
 * 1. 气泡容器模块
 * ==============================================*/
.mes {
  max-width: 350px;
  width: 500%;
  margin: 120px auto 120px;
  border-radius: 0px;
  /* 移除渐变背景和阴影 */
  background: url('https://i.postimg.cc/B6wFRztQ/retouch-2025052922341612.jpg') repeat-y; /* 添加重复方向 */
  background-size: 100% auto; /* 保持宽度适配 */
  background-attachment: local; /* 确保滚动时背景同步 */
  transition: transform 0.2s ease; /* 移除阴影过渡 */
  transform-origin: top center;
  position: relative;
  overflow: visible;
  box-shadow: none !important; /* 强制移除所有阴影 */
}

.mes:hover {
  transform: translateY(-2px);
  box-shadow: none !important; /* 确保悬浮状态无阴影 */
}


/* ==============================================
 * 2. 头像容器模块
 * ============================================== */
.mesAvatarWrapper {
  position: absolute;
  top: -190px;           /* 控制头像在气泡上方的位置 */
  left: 20%;            /* 水平居中 */
  transform: translateX(-50%);
  z-index: 10;
}

/* ==============================================
 * 3. 头像图像模块（可自定义形状）
 * ============================================== */
.mesAvatarWrapper .avatar {
  /* 基础尺寸 - 可自定义修改 */
  width: 100px;           /* 头像宽度 */
  height: 100px;          /* 头像高度 */

  /* 形状控制 - 默认圆形 */
  border-radius: 50%;    /* 圆形（50%），可修改为不同值创建椭圆或圆角矩形 */

  /* 外观样式 */
  overflow: hidden;
  border: 3px solid #fff;
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.15);
  transition: all 0.3s ease;
}

.mesAvatarWrapper .avatar img {
  width: 100%;
  height: 100%;
  object-fit: cover;
}


/* ==============================================
 * 4. 楼层显示
 * ============================================== */
.mes .mesIDDisplay {
    position: fixed;  /* 使用固定定位 */
    top: 200;           /* 固定在顶部 */
    left: 8%;        /* 水平居中 */
    transform: translateX(-50%); /* 精确居中 */
    z-index: 9999;    /* 确保在最顶层 */
    margin-top: 120px; /* 适当留白 */

    /* 简约样式 */
    padding: 2px 12px;
    background: rgba(255, 255, 255, 0.4); /* 半透明白底 */
    border-radius: 4px;
    box-shadow: 0 2px px rgba(0, 0, 0, 0.1);

    /* 保留原有样式 */
    cursor: default;
    opacity: 0.7;
    font-size: calc(var(--mainFontSize) * 0.9);
    font-weight: 600;
    color: #333; /* 增加颜色确保可读性 */
}

/* 其他元素保持原有样式 */
.mes .mes_timer, .mes .tokenCounterDisplay {
    cursor: default;
    opacity: 0.7;
    font-size: calc(var(--mainFontSize) * 0.9);
    font-weight: 600;
    text-align: center;
}
}

