<!DOCTYPE html>
<html lang="zh-CN">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>酷帅黑白风格复选框</title>
    <style>
        /* 精简后的黑白风格 */
        body {
            background: #fff; /* 白色背景 */
            display: flex;
            justify-content: center;
            align-items: center;
            min-height: 100vh;
            margin: 0;
            font-family: 'Segoe UI', 'Microsoft YaHei', sans-serif;
            transition: background 0.4s;
        }

        .container {
            background: #000;
            padding: 30px;
            border-radius: 15px;
            box-shadow: 0 10px 30px rgba(0, 0, 0, 0.15);
            text-align: center;
        }

        h1 {
            color: #fff;
            text-shadow: 0 2px 4px rgba(0, 0, 0, 0.3);
            margin-bottom: 30px;
            font-weight: 600;
            letter-spacing: 1px;
        }

        .checkbox-group {
            margin: 15px 0;
            display: flex;
            align-items: center;
            justify-content: space-between;
            width: 280px;
        }

        /* 核心样式 - 精简并修改为黑白风格 */
        input[type='checkbox'] {
            appearance: none;
            width: 20px; /* 横长 */
            height: 20px; /* 宽短 */
            border: 2px solid #000;
            border-radius: 0;
            cursor: pointer;
            position: relative;
            background: #fff;
            transition: all 0.3s;
            box-shadow: 0 2px 8px rgba(0, 0, 0, 0.2);
        }

        input[type='checkbox']:hover {
            transform: scale(1.05);
            box-shadow: 0 0 13px rgba(0, 0, 0, 0.3);
        }

        input[type='checkbox']:checked {
            background: #000;
            border-color: #333;
            animation: jelly 0.6s ease;
        }

        input[type='checkbox']:checked::after {
            content: '💽';
            position: absolute;
            top: 50%;
            left: 50%;
            transform: translate(-50%, -50%);
            color: #fff;
            font-size: 13px;
            font-weight: bold;
            text-shadow: 0 1px 3px rgba(255, 255, 255, 0.3);
        }

        #advancedMode:checked {
            background: #222;
            border-color: #000;
            box-shadow: 0 0 20px rgba(0, 0, 0, 0.25);
        }

        #advancedMode:checked::after {
            content: '✪';
            color: #fff;
            animation: pulse 1.5s ease-in-out infinite;
        }

        label {
            color: #fff;
            font-size: 14px;
            font-weight: 500;
            text-shadow: 0 1px 2px rgba(0, 0, 0, 0.2);
            letter-spacing: 0.5px;
            flex: 1;
            text-align: left;
        }

        /* 精简动画 */
        @keyframes jelly {
            0%, 100% { transform: scale(1); }
            30% { transform: scale(1.1); }
            60% { transform: scale(0.95); }
        }

        @keyframes pulse {
            0%, 100% { opacity: 1; }
            50% { opacity: 0.7; }
        }

        .divider {
            height: 1px;
            background: linear-gradient(to right, transparent, #444, transparent);
            margin: 20px 0;
        }

        .mode-indicator {
            color: #ddd;
            margin-top: 25px;
            font-size: 14px;
        }
    </style>
</head>
<body>
    <div class="container">
        <h1>黑白模式</h1>

        <div class="checkbox-group">
            <label for="basicMode">基础模式</label>
            <input type="checkbox" id="basicMode">
        </div>

        <div class="divider"></div>

        <div class="checkbox-group">
            <label for="advancedMode">高级模式</label>
            <input type="checkbox" id="advancedMode">
        </div>

        <div class="mode-indicator">当前状态: <span id="status">基础模式已禁用</span></div>
    </div>

    <script>
        document.addEventListener('DOMContentLoaded', function() {
            const basic = document.getElementById('basicMode');
            const advanced = document.getElementById('advancedMode');
            const status = document.getElementById('status');

            basic.addEventListener('change', function() {
                if (this.checked) {
                    status.textContent = '基础模式已启用';
                } else {
                    status.textContent = '基础模式已禁用';
                }
            });

            advanced.addEventListener('change', function() {
                if (this.checked) {
                    status.textContent = '高级模式已启用';
                } else {
                    status.textContent = '基础模式已禁用';
                }
            });
        });
    </script>
</body>
</html>

