/*——————框美化三——————*/
textarea {
  background-color: #ffffff;        /* 白色背景 */
  color: #000000;                  /* 黑色文本 */
  border: 2px solid #000000;       /* 黑色边框 */

  width: 100%;
  display: block;
  box-sizing: border-box;
  border-radius: 9px;
  padding: 7px 15px;
  font-family: 'Inter', 'system-ui', sans-serif;
  font-size: 0.8rem;
  line-height: 1.6;
  resize: vertical;
  max-height: 60vh;
  transition: all 0.2s ease;

  &:focus {
    border-color: #666666;         /* 深灰色边框 */
    outline: none;
  }

  &::placeholder {
    color: #999999;               /* 灰色占位符 */
  }

  &::-webkit-scrollbar {
    width: 6px;
  }

  &::-webkit-scrollbar-track {
    background: #f0f0f0;
  }

  &::-webkit-scrollbar-thumb {
    background-color: #b0b0b0;
    border-radius: 1px;
  }
}

