/*——————框美化四——————*/
.drawer-content select {
  width: 100%;
  padding: 2px 6px 2px 20px; /* 减小上下padding实现横长宽短 */
  appearance: none;
  -webkit-appearance: none;
  -moz-appearance: none;
  cursor: pointer;

  /* 酷帅黑白配色 */
  background-color: #FFFFFF; /* 纯白底色 */
  border: 2px solid #000000; /* 纯黑边框 */
  border-radius: 0; /* 直角更简约 */

  /* 移除所有阴影 */
  box-shadow: none;

  /* 保持动态图标 */
  background-image: url("https://i.postimg.cc/h48x2Fj1/retouch-2025052921242816.png");
  background-repeat: no-repeat;
  background-position: right -5px center;
  background-size: 100px;

  /* 黑色文字 */
  font-family: 'Quicksand', sans-serif;
  font-size: 10px;
  color: #000000; 
  letter-spacing: 0.7px;

  transition: all 0.1s cubic-bezier(0.175, 0.25, 0.32, 0.275);
  transform-origin: center;
}

.drawer-content select:hover {
  transform: scale(1.02);
  border-color: #333333; /* 深灰边框 */
  background-color: #F5F5F5; /* 浅灰底色 */
  box-shadow: none; /* 无阴影 */
}

.drawer-content select:focus {
  outline: none;
  border-color: #000000; /* 纯黑边框 */
  background-color: #FFFFFF; /* 纯白底色 */
  box-shadow: none; /* 无阴影 */
  animation: jellyFocus 0.9s ease;
}

.drawer-content select option {
  background: #FFFFFF; /* 白底 */
  color: #000000; /* 黑字 */
  padding: 2px 20px;
  margin: 4px 0;
  border-radius: 0; /* 直角 */
}

.drawer-content select option:hover {
  background: #EEEEEE !important; /* 浅灰悬停 */
  transform: translateX(8px);
  box-shadow: none; /* 无阴影 */
}

/* 保留动画 */
@keyframes jellyFocus {
  0% { transform: scale(5); }
  10% { transform: scale(1.05); }
  20% { transform: scale(0.98); }
  30% { transform: scale(1); }
}

